import{_ as t,o as r,c as o,a9 as p}from"./chunks/framework.D4xYp1Zt.js";const a="/images/religion-for-the-nonreligious/Evolution.png",n="/images/religion-for-the-nonreligious/Evolution-Plus.png",i="/images/religion-for-the-nonreligious/consciousness-binary.png",l="/images/religion-for-the-nonreligious/consciousness-spectrum.png",s="/images/religion-for-the-nonreligious/big-staircase2.png",g="/images/religion-for-the-nonreligious/normal-animal-brain1.png",h="/images/religion-for-the-nonreligious/Higher-Being.png",m="/images/religion-for-the-nonreligious/animal-higher-being1.png",c="/images/religion-for-the-nonreligious/chaotic-brain1.png",u="/images/religion-for-the-nonreligious/fog-head.png",f="/images/religion-for-the-nonreligious/substeps.png",w="/images/religion-for-the-nonreligious/animals-in-fog.jpg",b="/images/religion-for-the-nonreligious/cashier.jpg",_="/images/religion-for-the-nonreligious/gratitude2.jpg",d="/images/religion-for-the-nonreligious/good-thing.jpg",y="/images/religion-for-the-nonreligious/bad-thing.jpg",k="/images/religion-for-the-nonreligious/late-night.jpg",q="/images/religion-for-the-nonreligious/flat-tire.jpg",j="/images/religion-for-the-nonreligious/consequences1.jpg",v="/images/religion-for-the-nonreligious/animals-clump.jpg",W="/images/religion-for-the-nonreligious/happy-earth-land.png",T="/images/religion-for-the-nonreligious/Little-Earth.png",x="/images/religion-for-the-nonreligious/Hubble_Ultra_Deep_Field_NICMOS.jpg",P="/images/religion-for-the-nonreligious/life-timeline.png",S="/images/religion-for-the-nonreligious/long-timeline.png",B="/images/religion-for-the-nonreligious/Thing.png",A="/images/religion-for-the-nonreligious/atom.png",C="/images/religion-for-the-nonreligious/animals-embarrassed.png",N="/images/religion-for-the-nonreligious/cashier-2.png",E="/images/religion-for-the-nonreligious/Step-1-3-Circles.png",F="/images/religion-for-the-nonreligious/Step-4-Circle.png",D="/images/religion-for-the-nonreligious/Laughing.jpg",H="/images/religion-for-the-nonreligious/logo.png",L="/images/religion-for-the-nonreligious/pinit_fg_en_rect_gray_20.png",Q=JSON.parse('{"title":"Religion for the Nonreligious","description":"","frontmatter":{"title":"Religion for the Nonreligious","titleZh":"写给非信徒的宗教","date":"2014-10-19T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/10/religion-for-the-nonreligious.html","slug":"religion-for-the-nonreligious"},"headers":[],"relativePath":"posts/religion-for-the-nonreligious.md","filePath":"posts/religion-for-the-nonreligious.md","lastUpdated":1782886257000}'),R={name:"posts/religion-for-the-nonreligious.md"};function I(M,e,U,V,$,J){return r(),o("div",null,[...e[0]||(e[0]=[p('<h1 id="写给非信徒的宗教-·-religion-for-the-nonreligious" tabindex="-1">写给非信徒的宗教 · Religion for the Nonreligious <a class="header-anchor" href="#写给非信徒的宗教-·-religion-for-the-nonreligious" aria-label="Permalink to &quot;写给非信徒的宗教 · Religion for the Nonreligious&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/10/religion-for-the-nonreligious.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/10/religion-for-the-nonreligious.html</a> · 2014-10-19</p></blockquote><p><em><strong>注:</strong> 如果你想把这篇文章打印出来或离线阅读,PDF 可能是最好的选择。你可以<a href="https://gum.co/religion" target="_blank" rel="noreferrer">在这里购买</a>。</em></p><p><em>心灵……能把地狱变成天堂,也能把天堂变成地狱。</em> —— 约翰·弥尔顿 (John Milton)</p><p><em>心灵无疑是它自己的宇宙。</em> —— 艾伦·莱特曼 (Alan Lightman)</p><p>你上学,努力读书,拿到文凭,自我感觉良好。但你更有智慧了吗?</p><p>你找到一份工作,在工作中取得成绩,承担更多责任,拿到更高的薪水,跳槽到一家更好的公司,承担更多的责任,拿到更高的薪水,租下一间带停车位的公寓,不再自己洗衣服,还会买那种 9 美元一瓶、渣子沉在瓶底的果汁。但你更快乐了吗?</p><p>你做着各种各样的生活琐事——你买菜、读文章、剪头发、嚼东西、倒垃圾、买车、刷牙、拉屎、打喷嚏、刮胡子、伸懒腰、喝醉、往食物里撒盐、和某人上床、给笔记本充电、慢跑、清空洗碗机、遛狗、买沙发、拉窗帘、扣衬衫扣子、洗手、拉上包的拉链、设闹钟、整理头发、点午餐、对某人友善、看电影、喝苹果汁、把新的一卷纸巾装到架子上。</p><p>但当你日复一日、年复一年地做这些事,你作为一个人真的在以某种有意义的方式成长吗?</p><p>在<a href="https://waitbutwhy.com/2014/10/how-religion-got-in-the-way.html" target="_blank" rel="noreferrer">上一篇文章</a>里,我讲述了我自己是怎么一步步走上无神论者之路的——但也说了我在心满意足地为自己&quot;不信教&quot;感到自豪的同时,从未认真思考过要主动地进行内在的自我提升——这个过程中反而阻碍了我自身的进化。</p><p>这不仅仅是我个人的天真所致。整个社会都聚焦于肤浅的东西,所以它并不强调认真对待真正的成长。精神领域最主要的机构——宗教——倾向于把重点放在神性而非人本身,把救赎变成了终极目标,而不是自我提升。那些真正常常关注人类境况的领域——哲学、心理学、艺术、文学、励志读物等等——则更处于边缘位置,它们的工作彼此之间往往支离破碎。所有这一切构成了这样一个世界:内在成长很难被当作除了兴趣爱好、课外活动、生活蛋糕上的糖霜之外的东西来对待。</p><p>考虑到人的心灵是一片深不可测的复杂海洋,创造了我们现实的每一个部分,下功夫去搞清楚里面究竟在发生什么,似乎理应是更严肃的优先事项。就像一家成长中的企业需要清晰的使命、深思熟虑的战略和可衡量的指标一样,一个成长中的人也需要一个<em>计划</em>——如果我们想要有意义地进步,我们就必须定义目标、搞清楚如何达成、意识到路上的障碍,并有一套跨越这些障碍的策略。</p><p>当我一头扎进这个话题时,我开始思考自己的处境——我在进步吗?努力是有的——从这个博客的许多文章主题里就能看出来——但我没有成长模型,没有真正的计划,没有清晰的使命。只是在某个领域偶尔心血来潮时,漫无章法地尝试自我提升。所以我试着把这些零散的努力、哲学和策略整合进一个统一的框架——某种<em>坚实</em>的、我未来能抓住的东西——这篇文章我就来深入聊聊它。</p><h2 id="所以坐好-倒杯咖啡-把你的大脑掏出来放在面前的桌子上——你会想让它就在那儿-方便随时对照-因为我们要探索的是这么一个古怪、复杂的玩意儿。" tabindex="-1">所以坐好,倒杯咖啡,把你的大脑掏出来放在面前的桌子上——你会想让它就在那儿,方便随时对照,因为我们要探索的是这么一个古怪、复杂的玩意儿。 <a class="header-anchor" href="#所以坐好-倒杯咖啡-把你的大脑掏出来放在面前的桌子上——你会想让它就在那儿-方便随时对照-因为我们要探索的是这么一个古怪、复杂的玩意儿。" aria-label="Permalink to &quot;所以坐好,倒杯咖啡,把你的大脑掏出来放在面前的桌子上——你会想让它就在那儿,方便随时对照,因为我们要探索的是这么一个古怪、复杂的玩意儿。&quot;">​</a></h2><p><strong>目标</strong></p><p>智慧。稍后细说。</p><p><strong>我们怎么达到这个目标?</strong></p><p>通过意识到真相。当我说&quot;真相&quot;时,我不是那种烦人地把这个词说得神神叨叨、玄之又玄的人——我指的就是现实的实际事实。真相是我们所知道的和我们所不知道的组合——而对这两面都保持觉察,是通往智慧的关键。</p><p>简单吧?我们不必<em>知道</em>得比现在更多,我们只需要<em>意识到</em>我们知道什么、不知道什么。真相就摆在眼前,写在白板上——我们只需要看着白板,反思一下。只是有那么一件事——</p><p><strong>挡在我们路上的是什么?</strong></p><p>迷雾。</p><p>要理解这迷雾,我们先得搞清楚,我们不在这儿:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/Evolution.png" target="_blank" rel="noreferrer"><img src="'+a+'" alt="Evolution"></a></p><p>我们在这儿:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/Evolution-Plus.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="Evolution Plus"></a></p><p>情况也不是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/consciousness-binary.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="consciousness binary"></a></p><p>而是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/consciousness-spectrum.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="consciousness spectrum"></a></p><p>这个概念对人类来说真的很难消化,但它是成长的起点。宣称自己&quot;有意识&quot;让我们可以就此收工,不再想这事儿。我喜欢把它想象成一个意识阶梯:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/big-staircase2.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="big staircase"></a></p><p>蚂蚁比细菌更有意识,鸡比蚂蚁更有意识,猴子比鸡更有意识,人比猴子更有意识。那我们之上是什么?</p><p>A) 肯定有东西,而且 B) 我们理解它的程度,不会比一只猴子理解我们的世界和我们的思考方式更好。</p><p>没有理由认为这座阶梯不会一直向上延伸。比我们高几级的红色外星人看待人类意识的方式,就跟我们看待猩猩的意识差不多——他们可能觉得作为一种动物我们已经挺让人印象深刻的了,但当然,我们其实根本谈不上理解任何东西。我们最杰出的科学家也比不过他们的一个幼童。</p><p>对阶梯上更高处的绿色外星人来说,红色外星人的智力和意识水平,大概就跟我们眼中的一只鸡差不多。而当绿色外星人低头看<em>我们</em>时,它看到的是最简单的、被预编程好的小蚂蚁。</p><p>我们无法想象阶梯更高处的生命会是什么样子,但接受「更高的台阶确实存在」这个事实,并试着从那些台阶的视角来看待我们自己——这就是我们在这次思维练习中需要进入的关键心态。</p><p>眼下,我们先不管那些高得离谱的台阶,只把注意力放在紧挨着我们上方的那一级——那个浅绿色的台阶。那一级上的物种看我们的眼光,可能就像我们看一个三岁小孩——正在从一团简单与天真的模糊中<em>萌发出</em>意识。让我们设想一下:那个物种派了一个代表来观察人类,并把观察结果汇报给他的母星——他会怎么评价我们的思考方式和行为方式?我们身上哪些东西会让他印象深刻?哪些又会让他尴尬得直咧嘴?</p><p>我想他会很快看到人类心智内部正在进行的一场冲突。一方面,阶梯上人类下方的所有那些台阶,都是我们成长起来的地方。数亿年来针对残酷世界中动物生存而演化出的适应机制深深植根于我们的 DNA,我们体内的原始冲动催生了一大堆低阶品质——恐惧、小气、嫉妒、贪婪、即时满足,诸如此类。这些品质是我们动物过往的遗留物,至今仍是我们大脑的一个显要组成部分,在我们脑袋里制造出一整个由狭隘情绪和动机组成的动物园:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/normal-animal-brain1.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="normal animal brain"></a></p><p>但在过去六百万年里,我们的演化谱系经历了意识的迅速膨胀,以及一种地球上任何其他物种都做不到的惊人推理能力。我们在意识的阶梯上大踏步向上迈进,而且非常迅速——让我们把这个新兴的高等意识元素称作我们的「高等存在 (Higher Being)」。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/Higher-Being.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="Higher Being"></a></p><p>高等存在聪明绝顶,思维宏大,而且完全理性。但放在宏大的时间尺度上看,他在我们脑袋里是个非常新的房客,而那些原始的动物力量则古老得多,它们在人脑中共处一室,使这里成了一个奇怪的地方:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/animal-higher-being1.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="animal + higher being"></a></p><p>所以并不是说一个人<em>就是</em>那个高等存在,而这个高等存在是三岁——而是说,一个人是高等存在和那些低等动物的<em>组合</em>,他们融合在一起,成为了我们这个三岁的家伙。单独的高等存在会是一个更先进的物种,单独的那些动物则会是一个远为原始的物种,而正是他们这种独特的共存,才让我们成为了独特的人类。</p><p>随着人类的演化,高等存在开始苏醒,他环顾你的大脑,发现自己身处一片陌生而怪异的丛林,里面全是些强大的原始生物,他们完全搞不懂他是谁、是什么。他的任务是给你带来清晰的思维和高层次的思考,但周围一群动物在他的工作环境里踩来踩去,这活儿可不好干。而事情马上就要变得更糟。人类的演化让高等存在越来越有意识,直到有一天,他意识到了一件震惊的事:</p><p><em><strong>我们会死</strong></em></p><p>这是地球上任何物种第一次有足够的意识去理解这个事实,而这把大脑里那些动物——他们根本没被设计来处理这类信息——彻底吓疯了,让整个生态系统陷入混乱:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/chaotic-brain1.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="chaotic brain"></a></p><p>这些动物从未经历过这种恐惧,他们对这件事的抓狂——一种延续至今的抓狂——正是高等存在在试图为我们成长、学习、做决策时最不需要的东西。</p><p>那些肾上腺素飙升的动物在我们脑袋里横冲直撞,能够劫持我们的心智,遮蔽我们的思考、判断、自我意识以及对世界的理解。这些动物的集体力量,就是我所说的「迷雾 (the fog)」。动物越是主导局面,让我们对高等存在的思想和洞见充耳不闻、视而不见,我们脑袋周围的迷雾就越浓,常常浓到我们只能看清面前几厘米的东西:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/fog-head.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="fog head"></a></p><p>让我们回想一下前面说的目标以及通往它的路径——觉察真相。高等存在几乎在任何情况下都能看清真相。但当迷雾在我们周围浓密弥漫,遮住我们的眼睛耳朵、包裹住我们的大脑时,我们就无法接触到高等存在或他的洞见。这就是为什么持续觉察真相如此困难——我们迷失在雾里,根本看不见也想不到它。</p><p>而当那个外星代表结束观察、准备返回他的母星时,我猜他对我们问题的总结大概会是这样:</p><p><strong>更高存在与动物之间的战斗——试图穿透迷雾看清一切——是人类核心的内心挣扎。</strong></p><p>这场发生在我们脑袋里的战斗有很多条战线。我们在这里已经看过几条:更高存在(以理性决策者的身份)对抗<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">即时满足猴 (Instant Gratification Monkey)</a>;更高存在(以真实之声的身份)对抗那只被吓得半死的<a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">社会生存猛犸象 (Social Survival Mammoth)</a>;更高存在传达的信息——<a href="https://waitbutwhy.com/2013/11/life-is-picture-but-you-live-in-pixel.html" target="_blank" rel="noreferrer">人生不过是由一堆「今天」组成的</a>——在迷雾中对更好的明天的耀眼渴望里被迷失了。这些都是同一个核心冲突的组成部分:我们的原始过去与我们开明未来之间的冲突。</p><p>关于迷雾最操蛋的一点是,当你身在雾中时,雾会挡住你的视线,让你看不到自己正在雾中。雾最浓的时候,恰恰是你最意识不到它存在的时候——它让你陷入<em>无意识</em>。意识到迷雾的存在、学会如何识别它,是提升意识层次、成为一个更有智慧的人的关键第一步。</p><p>那么我们已经确定了:我们的目标是智慧,要抵达那里,我们需要尽可能地觉察真相,而挡在路上的主要障碍就是迷雾。让我们把镜头拉近到战场上,看看为什么「觉察真相」如此重要,以及我们该如何战胜迷雾抵达那里:</p><p><strong>战场</strong></p><p>无论我们多么努力,人类都不可能踏上意识阶梯上比我们高一级的那一格浅绿色台阶。我们那更高级的能力——更高存在——还没到那个层次。也许再过一两百万年吧。就目前而言,这场战斗唯一能发生的地方就是我们所居住的这一级台阶,所以我们要把镜头拉近到这里。我们需要聚焦于我们这一级台阶内部的迷你意识光谱,方法是把我们这一级台阶再拆成四小格:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/substeps.png" target="_blank" rel="noreferrer"><img src="'+f+'" alt="substeps"></a></p><p>爬上这道迷你意识阶梯,就是通往真相的道路、通往智慧的方式、我个人的成长使命,还有一堆我从没想过自己会说出口的陈词滥调式表述。我们只需要理解这个游戏,努力把它玩好。</p><p>让我们逐格来看,试着理解我们要面对的挑战,以及该如何前进:</p><p><strong>第一格:身处迷雾中的我们</strong></p><p>第 1 层是最低的一层,也是雾最浓的一层,不幸的是,对我们大多数人来说,这就是我们默认的存在状态。在第 1 层,雾完完全全把我们裹住,又厚又近,堵塞了我们的所有感官,让我们浑浑噩噩地过一辈子。在这一层,高等存在的思想、价值观和优先事项完全迷失在这令人目盲的浓雾里,淹没在我们脑袋里那些动物震耳欲聋的咆哮、啁啾、鸣笛、嚎叫和尖叫声中。这让我们变得:1) 心胸狭隘,2) 目光短浅,3) 愚蠢。我们一个一个来聊:</p><p><strong>1) 在第 1 层,你极度心胸狭隘,因为动物们在主导一切。</strong></p><p>当我审视人类所体验的那些形形色色能激发我们行动的情绪时,我看到的不是散乱的一片,而是清晰地分成两大类:一类是高等存在那种崇高的、以爱为基础的、高级的情绪;另一类是我们脑内动物那种狭隘的、以恐惧为基础的、原始的情绪。</p><p>而在第 1 层,我们完全被动物情绪灌醉了——它们在浓雾中冲我们咆哮。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/animals-in-fog.jpg" target="_blank" rel="noreferrer"><img src="'+w+'" alt="animals in fog"></a></p><p>这就是我们之所以斤斤计较、心怀嫉妒的原因,也是我们之所以能从别人的不幸中获得如此彻底的快感的原因。这就是我们害怕、焦虑、缺乏安全感的原因。这就是我们为什么会自我中心、自恋;为什么会虚荣、贪婪;为什么会思想狭隘、爱评判他人;为什么会冷漠、麻木,甚至残忍。也只有在第 1 层,我们才会感受到那种原始的「我们 vs. 他们」的部落主义,让我们仇视和自己不同的人。</p><p>在一群卷尾猴身上你也能找到几乎所有这些情绪——这说得通,因为归根结底,这些情绪都可以浓缩成动物生存的两大要义:自我保存和繁殖需求。</p><p>第 1 层的情绪野蛮又强悍,一把揪住你的衣领,当它们支配你的时候,高等存在和他那些崇高的、以爱为基础的情绪就被一脚踹进了下水道。</p><p><strong>2) 在第 1 层,你目光短浅,因为雾就在你脸前六英寸处,让你看不到大局。</strong></p><p>浓雾能解释各种各样毫无逻辑、短视得令人尴尬的人类行为。</p><p>不然的话,为什么会有人在祖父母或父母还在世的时候把他们视为理所当然,只是偶尔见见,难得对他们敞开心扉,几乎不问他们任何问题——而等他们过世之后,你却只能不停地想他们有多了不起、不敢相信自己当初居然没有好好珍惜和他们相处、进一步了解他们的机会?</p><p>不然的话,为什么人们会那么爱<a href="https://waitbutwhy.com/2013/07/7-ways-to-be-insufferable-on-facebook.html" target="_blank" rel="noreferrer">炫耀</a>——虽然只要能看到大局就会明白,你生活中的好事反正大家早晚都会知道,而且保持谦虚永远对自己更有利?</p><p>要不是因为浓雾,为什么会有人在工作中只做最低限度的事、在项目上偷工减料、还对自己付出的努力撒谎——任何有大局观的人都知道,在职场里,一个人的工作习惯真相最终会完完全全暴露在老板和同事面前,你根本骗不了任何人?为什么有人会执意<em>确保</em>所有人都知道自己为公司做了什么有价值的事情——明明显而易见的是,这样做太过明显,让人觉得你努力工作只是为了功劳,而如果你只是把事情做好、其中某件事<em>恰好</em>被注意到了,这对你在公司的长期声誉和受尊重程度反而帮助大得多?</p><p>如果不是因为浓雾,为什么会有人在餐厅账单上斤斤计较,或者在旅行时对谁付了什么钱记一本令人不快的死板账簿?现在读到这篇文章的每一个人,都能立刻给自己的每个朋友在小气到慷慨(或自私到体贴)的量表上打出一个准确的 1-10 分,而你靠站在小气这端省下的那几百块钱,相比慷慨所带来的那种更讨人喜欢、更受尊重的形象,<em>根本</em>不值得。</p><p>那么多身居高位的知名男性做出这种完全无法解释的决定——因为一场婚外情而毁掉自己毕生建立起来的事业和婚姻——除了浓雾,还能有什么别的解释?</p><p>为什么会有人为了微不足道的一点小利益就扭曲和放松自己的原则,而原则会影响你长期的自尊,微不足道的小利益却对长期<em>什么</em>都影响不了?</p><p>那么多人任由<a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">对别人怎么想的恐惧</a>来支配自己的生活方式,除此之外还能怎么解释?如果他们看得清楚,就会意识到 A) 这是做或不做一件事的糟糕理由,B) 反正也没人真的在想你——大家都埋在自己的生活里。</p><p>然后还有那些无数次的情况:某人不透明的眼罩让他们在错误的<a href="https://waitbutwhy.com/2014/02/pick-life-partner.html" target="_blank" rel="noreferrer">伴侣关系</a>、工作、城市、公寓、友谊等等中困了好几年、有时候几十年,直到最后终于做出改变,然后说「不敢相信我居然没早点这么做」,或者「不敢相信我居然看不出这有多不适合我」。他们绝对应该相信,因为这就是浓雾的力量。</p><p><strong>3) 在第一步,你非常、非常蠢。</strong></p><p>这种愚蠢的一种表现,就是我们一次又一次、一遍又一遍地犯同样明显的错误。<a href="#footnote-1-2610">1</a></p><p>最扎眼的例子,就是迷雾一次又一次地说服我们:某些东西会让我们幸福——而实际上它们根本不会。迷雾在我们面前摆出一排胡萝卜,告诉我们这些就是幸福的钥匙,<a href="https://waitbutwhy.com/2013/11/life-is-picture-but-you-live-in-pixel.html" target="_blank" rel="noreferrer">让我们忘掉今天的幸福</a>,把所有希望寄托在未来能获得的所有幸福上,因为我们马上就能拿到那些胡萝卜。</p><p>尽管迷雾一次又一次地证明它根本不懂人类的幸福是怎么回事——尽管我们已经有过无数次经历:终于拿到一个胡萝卜,爽到爆棚,然后眼睁睁看着那份幸福在几天之内滑回到我们的默认水平——我们还是继续上当。</p><p>这就好比你请了个营养师来帮你解决疲劳问题,他告诉你,关键是只要你累了就喝一杯浓缩咖啡。你试了,觉得这营养师简直是天才,直到一个小时后咖啡效果消失,你像被砸了一记铁砧一样重新陷入疲惫。你回去找营养师,他给你同样的建议,你又试了一次,结果一模一样。到这份上,故事应该就结束了吧?你会把这个营养师炒了对吧?那为什么一涉及到幸福和满足感,我们对迷雾给的建议就这么好骗呢?</p><p>而迷雾比那个营养师危害大得多,因为它不仅给我们烂到家的建议——<strong>迷雾本身就是不幸福的根源</strong>。解决疲劳的唯一真正办法是<em>睡觉</em>,而持久提升幸福感的唯一真正办法,是在对抗迷雾这场战役里取得进展。</p><p>心理学里有个概念叫「享乐跑步机 (The Hedonic Treadmill)」,意思是人类有一个稳定的默认幸福水平,当好事或坏事发生时,幸福感短暂波动之后,我们总是会回到那个默认水平。在第 1 阶,这当然是完全成立的——毕竟想在迷雾里永久变得更幸福,就像在开着水的淋浴下想把身子擦干一样。</p><p>但我拒绝相信,能建摩天大楼、写交响乐、飞上月球、还能搞懂希格斯玻色子是什么的这个物种,会没本事从跑步机上下来,真正意义上地做出改善。</p><p>我觉得实现这一点的方式,就是学会攀爬这道意识阶梯,把更多时间花在第 2、3、4 阶上,少一点时间无意识地陷在迷雾里。</p><p><strong>第 2 阶:让迷雾变薄,显露语境</strong></p><p>人类能做一件地球上其他任何生物都做不到的了不起的事——他们能<em>想象</em>。你给一只动物看一棵树,它看到的就是一棵树。只有人能想象出 40 年前沉入土里的那颗橡子、这棵树三岁时那根瘦弱的小茎、冬天里它光秃秃的样子该有多凄凉、以及最终它枯死了横躺在同一片地方的画面。</p><p>这就是我们脑中「高等存在」的魔力所在。</p><p>另一方面,你脑袋里那些动物,和它们现实世界中的亲戚一样,只能看见一棵树,一旦看见,就会基于自己原始的需求瞬间对它做出反应。当你处于第 1 阶时,那个由动物操控的无意识状态甚至根本不记得「高等存在」的存在,它那些天才般的能力就白白浪费掉了。</p><p>第 2 阶的核心,就是把迷雾稀释到足够稀薄,让「高等存在」的思想和能力能够进入你的意识,让你能够看到生活中所发生之事的<em>背后</em>和<em>周围</em>。第 2 阶就是把<em>语境</em>带进你的意识,从而揭示出一个远远更深、更微妙的真相。</p><p>有很多活动或事情可以帮你稀释迷雾。举三个例子:</p><ol><li><p>通过教育、旅行和人生经历更多地了解世界——随着你的视角变宽,你能看见一个更清晰、更准确的真相版本。</p></li><li><p>主动反思。这是日记能帮上忙的地方,或者心理咨询,后者本质上就是在一位迷雾专家的帮助下检视你自己的大脑。有时一个假设性的问题可以充当「防雾眼镜」,让你透过迷雾清楚地看见某样东西——比如「如果钱不是问题,我会怎么做?」或「如果是别人碰上这事我会怎么建议他?」或「等我 80 岁的时候,会不会后悔没做这件事?」这些问题是一种偷偷向「高等存在」征询意见的方式,不让那些动物察觉发生了什么,这样它们才会保持冷静,「高等存在」才能真正开口——就像父母不想让四岁的孩子听懂他们说什么时,会把某个单词一个字母一个字母地拼出来。<a href="#footnote-2-2610">2</a></p></li><li><p>冥想、锻炼、瑜伽等——那些能让大脑无意识的喋喋不休安静下来、也就是让迷雾沉淀的活动。</p></li></ol><p>但稀释迷雾最简单、最有效的方法,就是仅仅<em>意识到</em>它的存在。当你知道迷雾存在、明白它是什么、以及它会以哪些不同形式出现,并学会识别自己何时深陷其中时,你就削弱了它主宰你人生的能力。如果你不知道自己何时身处第 1 阶,你就永远走不到第 2 阶。</p><p>进入第 2 阶的方法,就是记得对你所见之物、所遇之事以及所做决定背后和周围的语境保持觉察。就这么简单——对迷雾保持自觉,记得去看整个语境,就能让你保持清醒、觉知现实,而且正如你即将看到的,这会让你成为一个比第 1 阶时好得多的自己。举几个例子——</p><p>一个粗鲁的收银员在第 1 阶和第 2 阶眼中分别是这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/cashier.jpg" target="_blank" rel="noreferrer"><img src="'+b+'" alt="cashier"></a></p><p>感恩是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/gratitude2.jpg" target="_blank" rel="noreferrer"><img src="'+_+'" alt="gratitude"></a></p><p>发生了一件好事:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/good-thing.jpg" target="_blank" rel="noreferrer"><img src="'+d+'" alt="good thing"></a></p><p>发生了一件坏事:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/bad-thing.jpg" target="_blank" rel="noreferrer"><img src="'+y+'" alt="bad thing"></a></p><p>那种深夜躺在床上时,一切突然都变得糟糕透顶的现象:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/late-night.jpg" target="_blank" rel="noreferrer"><img src="'+k+'" alt="late night"></a></p><p>爆胎:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/flat-tire.jpg" target="_blank" rel="noreferrer"><img src="'+q+'" alt="flat tire"></a></p><p>长远的后果:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/consequences1.jpg" target="_blank" rel="noreferrer"><img src="'+j+'" alt="consequences"></a></p><p>审视语境让我们意识到,对于大多数情况我们其实知道很多(也让我们意识到自己不知道什么,比如那位收银员今天过得怎么样),它提醒我们人、生活和情境的复杂与微妙。当我们在第 2 阶时,这种更广阔的视角和更清晰的认知让我们感到更平静,不再害怕那些其实并不可怕的东西,而那些从恐惧中汲取力量、靠无意识茁壮成长的动物们——突然看起来就有点滑稽了:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/animals-clump.jpg" target="_blank" rel="noreferrer"><img src="'+v+'" alt="animals clump"></a></p><p>当那些小心眼的动物情绪没那么嚣张时,更高等生命 (Higher Being) 的高阶情感——爱、慈悲、谦卑、共情等等——就开始亮起来。</p><p>好消息是,到达第 2 阶不需要任何学习——你的高等生命本来就懂得所有这些人生情境的语境。它不需要费力,不需要额外的信息或专业知识——你只需要有意识地去想着待在第 2 阶而不是第 1 阶,你就到那儿了。你现在光是读着这段话,大概就已经在第 2 阶了。</p><p>坏消息是,要<em>长时间待在</em>第 2 阶极其困难。这里有个第 22 条军规式的死循环:要一直意识到迷雾的存在并不容易,因为迷雾本身就让你陷入无意识。</p><p>这就是眼前的第一个挑战。你没法摆脱迷雾,也没法一直让它保持稀薄,但你可以变得更善于察觉它什么时候变浓,并培养出有效的策略,在你有意识地聚焦于它时把它拨散开。如果你在成功地进化,那么随着年龄增长,你应该越来越多地待在第 2 阶,越来越少地陷在第 1 阶。</p><p><strong>第 3 阶:令人震惊的现实</strong></p><h2 id="我-原子构成的宇宙-宇宙中的一个原子。——-理查德·费曼-richard-feynman" tabindex="-1">*我……原子构成的宇宙……宇宙中的一个原子。——*理查德·费曼 (Richard Feynman) <a class="header-anchor" href="#我-原子构成的宇宙-宇宙中的一个原子。——-理查德·费曼-richard-feynman" aria-label="Permalink to &quot;*我……原子构成的宇宙……宇宙中的一个原子。——*理查德·费曼 (Richard Feynman)&quot;">​</a></h2><p>第 3 阶是事情开始变得诡异的时候。即使在更为开悟的第 2 阶,我们还是有点儿觉得自己身处这里:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/happy-earth-land.png" target="_blank" rel="noreferrer"><img src="'+W+'" alt="happy earth land"></a></p><p>尽管这种感觉很惬意,但它完全是幻觉。我们过日子的时候,感觉自己就活在这片绿棕相间的大地上,头顶蓝天,身边有花栗鼠和毛毛虫。可实际上,情况是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/Little-Earth.png" target="_blank" rel="noreferrer"><img src="'+T+'" alt="Little Earth"></a></p><p>但更真实的情况,其实是这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/Hubble_Ultra_Deep_Field_NICMOS.jpg" target="_blank" rel="noreferrer"><img src="'+x+'" alt="IDL TIFF file"></a></p><p>我们也倾向于以为情况是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/life-timeline.png" target="_blank" rel="noreferrer"><img src="'+P+'" alt="life timeline"></a></p><p>而实际上,是这样的:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/long-timeline.png" target="_blank" rel="noreferrer"><img src="'+S+'" alt="long timeline"></a></p><p>你甚至可能以为自己是个&quot;东西&quot;。是吧?</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/Thing.png" target="_blank" rel="noreferrer"><img src="'+B+'" alt="Thing"></a></p><p>不,你是一大堆这玩意儿:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/atom.png" target="_blank" rel="noreferrer"><img src="'+A+'" alt="atom"></a></p><p>这是我们那小楼梯上下一层的真相,而我们的大脑其实处理不了它。让一个人真正理解宇宙的浩瀚、<a href="https://waitbutwhy.com/2013/08/putting-time-in-perspective.html" target="_blank" rel="noreferrer">时间的永恒</a>、或原子的渺小,就像让一只狗用后腿站起来——你集中精力是能做到,但很费劲,而且撑不了多久。<a href="#footnote-3-2610">3</a></p><p>你随时都可以<em>想想</em>这些事实——宇宙大爆炸发生在 138 亿年前,大约是人类存在时间的 13 万倍;如果太阳是纽约的一个乒乓球,那么离我们最近的恒星就是亚特兰大的一个乒乓球;银河系大到如果你按比例做一个跟美国一样大的模型,你还得用显微镜才能看见太阳;原子小到一粒盐里的原子数量,大约等于<a href="http://www.hawaii.edu/suremath/jsand.html" target="_blank" rel="noreferrer">地球上所有海滩</a>上沙粒的总数。但偶尔,当你深深沉思其中某个事实,或者你和对的人正好在深夜聊起对的话题,或者你凝视着星空,或者你太较真地去想&quot;死亡&quot;到底意味着什么——你就会有一个*&quot;卧槽&quot;的瞬间*。</p><p>真正的「Whoa 时刻」(Whoa moment) 很难遇到,遇到了也难以维持多久,就像我们那只狗站着的困难一样。<em>思考</em>这个层级的现实,就像看一张壮丽的大峡谷照片;而 Whoa 时刻则像是<em>身处</em>大峡谷之中——这两种体验类似,但又有着天壤之别。事实可以很迷人,但只有在 Whoa 时刻,你的大脑才真正把握住了真实的现实。在 Whoa 时刻,你的大脑短暂地超越了它被设计出来去做的事情,让你瞥见我们存在的<em>令人震惊</em>的真相。而 Whoa 时刻就是你抵达第 3 阶的方式。</p><p>我爱 Whoa 时刻。它们让我产生一种敬畏、狂喜、悲伤和惊叹的强烈混合感。最重要的是,它们让我感到荒谬而深刻的谦卑——而那种程度的谦卑会对一个人产生奇怪的作用。在那些时刻,宗教徒们用的所有那些词——敬畏、崇拜、奇迹、永恒的连接——都变得完美地说得通。我想跪下来<em>臣服</em>。这就是我感到有灵性的时刻。</p><p>而在那些转瞬即逝的时刻,没有迷雾——我的高等存在完全流畅地运转,能以完美的清晰度看到一切。平时复杂的道德世界突然变得清澈透明,因为在第 3 阶,唯一可想象的情绪都是最高级别的。任何形式的小气或仇恨在第 3 阶都是可笑的概念——没有迷雾遮蔽事物,动物们完全赤裸,暴露出它们那些可悲的小生物本质。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/animals-embarrassed.png" target="_blank" rel="noreferrer"><img src="'+C+'" alt="animals embarrassed"></a></p><p>在第 1 阶,我会怼回那个粗鲁的收银员,他居然有胆<em>对我</em>当个<em>混蛋</em>。在第 2 阶,这份粗鲁并不能让我动摇,因为我知道那是关于他的,不是关于我的,而且我根本不知道他今天过得怎样、这辈子经历过什么。在第 3 阶,我把自己看作是在浩瀚宇宙中一次奇迹般的原子排列,在无尽的永恒中的一瞬间聚在一起,形成了<em>一段意识的时光</em>——这就是我的生命……我看到那位收银员是<em>另一段意识时光</em>,恰巧存在于<em>和我同一小片时空之中</em>。而在第 3 阶,我唯一能对他产生的情感就是爱。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/cashier-2.png" target="_blank" rel="noreferrer"><img src="'+N+'" alt="cashier 2"></a></p><p>在 Whoa 时刻那种超越性的意识层级里,我以异常的清晰度看到每一次互动、每一个动机、每一条新闻头条——而困难的人生抉择也变得清楚得多。我感到<em>智慧</em>。</p><p>当然,如果这是我的常态,我现在应该在缅甸某座山上教僧侣了,而我没在任何地方教任何僧侣,因为这不是我的常态。「顿悟时刻 (Whoa moments)」很稀有,而且顿悟没多久,我就又掉回下面继续当个人类。但第三级台阶带来的那种情绪和清明感如此强大,以至于哪怕你从台阶上跌落,其中一部分依然会留下来。每次你羞辱一次那两只动物,它们未来对你的支配力就削弱一点。这就是为什么第三级如此重要——尽管我认识的人没有一个能永久居住在第三级,但定期造访能极大地帮你打赢那场持续进行的「第一级 vs 第二级」的战争,让你成为一个更好、更快乐的人。</p><p>第三级台阶也是对那些指责无神论者不道德、犬儒或虚无主义的人,以及疑惑「没有来世的希望与激励,无神论者怎么在人生中找到意义」的人的回答。那种视角本身就是第一级台阶看无神论者的方式——把地球上的生命视为理所当然,并假设任何正面的冲动或情感都必然来自生活以外的境遇。而在第三级,我觉得能活着简直是无比幸运,我无法相信我作为一群「能思考原子的原子」是多么酷的事——在第三级,生命本身就足以让我兴奋、充满希望、充满爱、心怀善意。但第三级之所以可能,是因为科学为我们清出了通往它的道路,这也是为什么卡尔·萨根 (Carl Sagan) 说「科学不仅与灵性兼容;它本身就是一种深刻的灵性源泉」。在这个意义上,科学就是这个框架的「先知」——它向我们揭示新的真理,并给我们一个通过接触真理来改变自我的机会。</p><p>那么到目前为止总结一下——在第一级,你被困在一个妄想泡泡里,第二级把它戳破。在第二级,对生命有了更多清明,但它又被包在一个更大的妄想泡泡里,而第三级把这个泡泡戳破。但第三级本该是彻底的、无雾的真理清明——那还怎么可能有下一级呢?</p><p><strong>第四级台阶:巨大的未知</strong></p><h2 id="如果有一天我们以为自己已经彻底理解了我们是谁、我们从何而来-那我们就失败了。——-卡尔·萨根" tabindex="-1">*如果有一天我们以为自己已经彻底理解了我们是谁、我们从何而来,那我们就失败了。——*卡尔·萨根 <a class="header-anchor" href="#如果有一天我们以为自己已经彻底理解了我们是谁、我们从何而来-那我们就失败了。——-卡尔·萨根" aria-label="Permalink to &quot;*如果有一天我们以为自己已经彻底理解了我们是谁、我们从何而来,那我们就失败了。——*卡尔·萨根&quot;">​</a></h2><p>到目前为止,这个游戏大部分时候都是在清雾,好让我们尽可能清醒地意识到——作为个人以及作为一个物种——我们对真理的认知:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/Step-1-3-Circles.png" target="_blank" rel="noreferrer"><img src="'+E+'" alt="Step 1-3 Circles"></a></p><p>在第四级,我们被提醒起<em>完整的</em>真相——即以下这幅图:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/Step-4-Circle.png" target="_blank" rel="noreferrer"><img src="'+F+'" alt="Step 4 Circle"></a></p><p>事实是,任何关于我们完整现实的讨论——关于宇宙或我们存在的真相——如果不承认那一大团构成了几乎全部现实的紫色斑块,就是一场彻底的妄想。</p><p>但你懂人类的——他们一点也不喜欢那团紫色的斑点。从来都不喜欢。这团斑点让人类恐惧、让人类难堪,而我们有着悠久的传统,那就是干脆否认它的存在,这就好比住在海边却假装大海不存在。我们只会跺跺脚,宣称<em>这一次</em>我们终于把一切都搞明白了。在宗教这边,我们编造神话并宣称其为真理——即便是一位读到这段话、坚信自己那本经书为真的虔诚信徒,也会同意我的看法:世界上其他几千本经书都是杜撰的。而在科学这边,我们始终天真地相信,「意识到自己对现实的理解错得离谱」这种事只发生在过去。</p><p>一个突破性的新发现颠覆我们对现实的理解,就像人类正在读的这本史诗级悬疑小说里的惊人反转,而科学进步中经常点缀着这样的反转——地球是圆的、太阳系是日心说而非地心说、亚原子粒子或其他星系的发现,以及进化论,略举几例。那么,在了解所有这些突破的情况下,历史上最伟大的科学家之一开尔文勋爵怎么可能在 1900 年说出:「物理学中已经没有什么新东西可以发现了。剩下的只是越来越精确的测量。」<a href="#footnote-4-2610">4</a>——也就是说,<em>这一次</em>,所有的反转真的都结束了。</p><p>当然,开尔文和历史上其他所有傲慢的科学家一样错得离谱——广义相对论紧接着量子力学理论,会在接下来的一个世纪里把科学一次次掀翻在地。</p><p>即使我们今天承认未来还会有更多反转,我们大概还是<em>有点</em>倾向于认为,我们已经搞清楚了<em>大部分</em>重要的事情,对现实的了解远比那些认为地球是平的人更接近全貌。在我听来,这就好比:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/Laughing.jpg" target="_blank" rel="noreferrer"><img src="'+D+'" alt="Laughing"></a></p><p>事实是,我们得记住,<em>我们并不知道宇宙是什么</em>。它是一切吗?它只是某个泡沫翻腾的多重宇宙里的一个小气泡?或者它根本不是气泡,只是一种视错觉般的<a href="http://www.nature.com/news/simulations-back-up-theory-that-universe-is-a-hologram-1.14328" target="_blank" rel="noreferrer">全息投影</a>?我们知道有大爆炸,但那真的是一切的开端吗?<a href="https://waitbutwhy.com/table/why-is-there-something-instead-of-nothing" target="_blank" rel="noreferrer">是<em>某物</em>从<em>虚无</em>中诞生,还是这只是一长串膨胀/坍缩循环里最近的一次?</a><a href="#footnote-5-2610">5</a> 我们完全不知道暗物质是什么,只知道宇宙里有一大堆一大堆的暗物质。而当我们讨论<a href="https://waitbutwhy.com/2014/05/fermi-paradox.html" target="_blank" rel="noreferrer">费米悖论 (Fermi Paradox)</a>的时候,已经很清楚了:科学<em>根本</em>不知道外面有没有其他生命,也不知道它们的文明发展到什么水平。那弦理论呢?它号称是统一物理世界两大宏伟却看似毫无关联的理论——广义相对论和量子力学——的秘密钥匙。它要么是我们迄今提出过<em>最</em>伟大的理论,要么就是彻头彻尾的错误,而这场争论的两边都站着伟大的科学家。而作为外行,我们只需看看这两个已被广泛接受的理论,就能意识到现实可以和它表面看起来的样子有多么不同:比如广义相对论告诉我们,如果你飞到一个黑洞旁边,在强引力下绕它转几圈,几小时后回到地球,你会发现地球上已经过了<em>几十年</em>。而这跟量子力学告诉我们的疯狂玩意儿相比,还只是一支冰淇淋甜筒的水平——比如宇宙两端的两个粒子<a href="http://www.scientificamerican.com/article/quantum-entanglement/" target="_blank" rel="noreferrer">神秘地关联着彼此的行为</a>,或者一只猫在你去看它之前同时<a href="http://news.nationalgeographic.com/news/2013/08/130812-physics-schrodinger-erwin-google-doodle-cat-paradox-science/" target="_blank" rel="noreferrer">既是活的又是死的</a>。</p><p>而问题是,我刚才提到的这一切,还都在我们理解能力的范围之内。正如我们前面所说,和更进化的意识层级相比,我们可能就像三岁小孩、猴子或者蚂蚁——所以我们凭什么假设自己有<em>能力</em>理解那个紫色斑块里的所有东西?一只猴子无法理解地球是一颗圆形的行星,更别提太阳系、银河系或整个宇宙的存在了。你可以花好几年时间试着向猴子解释,它也不可能懂。那么,<em>即使有一个更聪明的物种拼尽全力向我们解释</em>,又有哪些东西是我们完全无法领会的?可能几乎是所有东西。</p><p>思考这种超级大格局的时候,其实只有两个选项:要么谦卑,要么荒谬。</p><p>人类因为害怕而假装笃定,这件事其实很荒谬——想想看,在古早时代,当我们表面上看起来是万物的中心时,不确定性之所以吓人,是因为它让我们的现实看起来比我们以为的要惨淡得多——但现在,随着我们揭开了这么多真相,作为个体和物种的我们,处境看起来<em>极其</em>惨淡,所以我们的恐惧应该<em>欢迎</em>不确定性才对。既然我的默认前景是,我还剩下寥寥几十年,然后就是永恒的不存在,那么&quot;我们可能完全搞错了&quot;这件事,对我来说简直是天大的希望。</p><p>讽刺的是,当我的思考爬到这段扎根于无神论的楼梯顶端时,&quot;某种在我们看来近乎神性的东西可能存在&quot;这个念头,反倒不再显得那么荒唐了。对于所有人类创造出来的关于某种神性高等力量的概念,我仍然是彻头彻尾的无神论者——在我看来,它们全都宣称了太多的笃定。但是,一种超级先进的力量会不会存在?看起来相当有可能。我们会不会是被某个比我们更大的东西/某个人创造出来的,或者活在一个自己都没意识到的模拟系统里?当然有可能——我是个三岁小孩,记得吗,我凭什么说不呢?</p><p>对我来说,完全理性的逻辑告诉我:对地球上所有的宗教持无神论立场,对我们存在的本质、或某个更高存在者是否存在这件事,则彻底持不可知论。我不是通过任何形式的信仰得出这个结论的,只是靠逻辑。</p><p>我觉得第 4 层在思维上让人脑洞大开,但我不确定自己能不能像有时对第 3 层那样,以某种精神层面的方式真正抵达它——第 4 层的&quot;哇噢&quot;时刻,大概是留给爱因斯坦级别的思想家的——不过就算我没法把脚踩上第 4 层,我至少能知道它在那儿,知道它意味着什么,并且时不时提醒自己它的存在。那么这对身为人类的我有什么用呢?</p><p>嗯,还记得我在第 3 层提到的那种强大的谦卑感吗?第 4 层把它乘以了 100。基于我刚才讨论过的那些原因,它让我觉得更有希望。它还让我心悦诚服地接受一个事实:我永远无法理解到底发生了什么——这让我觉得可以松开方向盘,靠回椅背,放松下来,好好享受这趟旅程。这样一来,我觉得第 4 层能让我们更活在当下——如果我只是一颗漂浮在自己无法理解的海洋里的分子,那不如就享受它吧。</p><p>第 4 层能为人类做的事情,是帮助粉碎&quot;笃定&quot;这个概念。笃定是原始的,会导向&quot;我们 vs. 他们&quot;的部落主义,会挑起战争。我们应该在不确定性中团结,而不是因为编造出来的笃定而分裂。人类越是转过身去看那团紫色大斑,我们就过得越好。</p><p><strong>为什么智慧才是终极目标</strong></p><p>没什么比临终之榻更能驱散迷雾——正因如此,人总是要到那一刻才能清楚地看到自己本该有哪些不同的做法——真希望我少花点时间工作;真希望我多和妻子交流;真希望我多出去旅行;等等。个人成长的目标,应该是趁生命还在进行时就获得这种临终顿悟,这样你才真的能做点什么。</p><p>而要做到这一点,就得尽早、尽可能多地积累智慧。对我来说,智慧是人这辈子最值得去追求的东西。它是那个大目标——是那把伞,其他所有目标都归入其下。我相信自己只有一次、且仅有一次活着的机会,我想以最充实、最有意义的方式度过它——这对我来说是最好的结果,而且这样我也能为世界做更多的好事。智慧让人真正明白&quot;充实而有意义&quot;到底意味着什么,并给他们勇气去做那些能通往此处的选择。</p><p>虽然人生阅历确实有助于增长智慧,但我觉得智慧其实早已在我们每个人的脑袋里——它就是&quot;更高存在&quot;所知道的一切。当我们不智慧时,是因为我们接触不到&quot;更高存在&quot;的智慧,它被迷雾埋住了。迷雾是反智慧的,当你沿着阶梯往上走、进入更清明的地方时,智慧不过是意识提升之后自然而然的副产品。</p><p>我在某个时刻明白了一件事:变<em>老</em>或者长<em>高</em>,和<em>长大</em>不是一回事。当一个大人,取决于你的智慧水平和心智视野的大小——事实证明这跟年龄并没有特别的关联。过了某个年纪,长大其实就是要战胜自己的迷雾,这跟这个人有关,跟年龄无关。我认识一些极其睿智的长辈,但也有不少跟我年纪差不多的人,他们在很多事情上似乎比自己的父母睿智得多。走在成长之路上、随年龄增长而迷雾渐薄的人,会越活越有智慧;但我发现反过来的情况也会发生在那些不主动成长的人身上——他们周围的迷雾会随年龄越结越硬,他们实际上会变得越来越不清醒,对一切也越来越笃定。</p><p>回想我认识的人,我意识到自己对一个人的尊敬和钦佩程度,几乎完全取决于我认为这个人有多睿智、多清醒。我心中最敬重的那些人,是我生命中真正的&quot;大人&quot;——而他们的年龄天差地别。</p><p><strong>从这个框架再看看宗教:</strong></p><p>这段讨论有助于澄清我对传统组织化宗教的问题。宗教世界里有大量的好人、好想法、好价值观和好智慧,但在我看来,这些东西的存在似乎是「尽管有宗教」而不是「因为有宗教」。想用宗教来实现成长,需要一种创新的解读方式,因为从根本上说,大多数宗教对待人的方式更像对待小孩,而不是推动他们成长。今天的许多宗教利用人们的迷雾,搞「信这个,否则……」式的恐吓,而它们的经典书籍常常成为「我们 vs. 他们」这种分裂主义的战斗号角。它们让人从古代经文中寻找答案,而不是从心灵深处寻找;它们在是非对错上那种顽固的确定感,常常让它们在社会议题的演进中远远落在队伍最后。它们在历史问题上的确定感,最终把追随者主动推离真相——比如<a href="http://www.gallup.com/poll/21814/evolution-creationism-intelligent-design.aspx" target="_blank" rel="noreferrer">42% 的美国人</a>就被剥夺了了解进化论真相的机会。(一个更严重的阶梯罪犯是令人厌恶的美国政治世界,那种文化整个活在第 1 阶,政客直接迎合人们的动物本能,刻意回避第 2 到第 4 阶的任何东西。)</p><p><strong>那我是什么?</strong></p><p>是的,我是无神论者,但无神论作为一种成长模式,就跟「我不喜欢轮滑」作为一种健身策略差不多。</p><p>所以我要给自己发明一个词——我是一名「真理主义者 (Truthist)」。在我的框架里,真理是我一直在寻找的东西,真理是我崇拜的东西,而学会更容易、更频繁地看到真理,就是通向成长的路。</p><p>在真理主义里,目标是随着时间变得越来越有智慧,而每当你足够清醒,能够看到关于人、情境、世界或宇宙的真相时,智慧就会自己落到你腿上。迷雾就是挡在你面前的东西,让你无意识、有妄念、心胸狭窄,所以日常的关键成长策略就是保持对迷雾的觉察,并训练你的大脑去尝试看清任何情境下的完整真相。</p><p>随着时间推移,你希望自己的 [待在第 2 阶的时间] / [待在第 1 阶的时间] 这个比值每年都能上升一点,你希望自己越来越擅长诱发第 3 阶的「哇哦」时刻,越来越擅长提醒自己第 4 阶那团紫色斑点。如果你能做到这些事,我觉得你就是在以最好的方式演化,而这会对你生活的方方面面产生深远影响。</p><p>就这样。这就是真理主义。</p><p>我是一个好的真理主义者吗?还行吧。比以前的我要好,但还有很长的路要走。不过定义这个框架会有帮助——我会知道该把注意力放在哪里、该警惕什么、该怎么评估自己的进展,这能帮我确认自己是真的在进步,也能让成长更快一些。</p><p>为了帮我时刻不忘使命,我做了一个真理主义的 logo:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/10/logo.png" target="_blank" rel="noreferrer"><img src="'+H+'" alt="logo"></a></p><p>这就是我的符号,我的咒语,我的 WWJD——当好事或坏事发生时,当重大决策摆在眼前时,或者只是在平常的日子里,我可以看看它,提醒自己留意迷雾,别忘了大局。</p><p><strong>那你呢?</strong></p><p>我给你的挑战是:为你自己确定一个词,准确概括你的成长框架。</p><p>如果基督教是你的信仰,而且它真的在帮你成长,那这个词可以是「基督徒 (Christian)」。也许你已经有了自己清晰、明确的进阶策略,只是需要给它起个名字。也许「真相主义 (Truthism)」戳中了你,和你原本的思维方式很接近,那你想试试和我一起当个「真相主义者 (Truthist)」也行。</p><p>或者,也许你根本不知道你的成长框架是什么,或者你正在用的那套根本不管用。如果 A) 你觉得过去几年里自己没有以任何有意义的方式进化过,或者 B) 你没办法用真正对你有分量的推理来支撑你的价值观和人生哲学,那你就需要找一个新的框架了。</p><p>要做到这点,只需问问你自己我问过自己的那些问题:你想<em>朝着</em>什么目标进化(为什么是那个目标),通往那里的路径是什么样的,什么在阻碍你,你要怎么克服那些障碍?你日常层面的实践是什么,你的进展从一年到下一年应该是什么样子?最重要的是,你怎么保持坚强、把这套实践坚持很多年、而不是四天就撂挑子?想清楚之后,给这个框架起个名字,做一个符号或咒语。(然后在评论里分享你的策略,或者发邮件告诉我,因为把它讲清楚有助于在你脑子里把它理清,而且别人听听你的框架也挺有用挺有意思的。)</p><h2 id="我希望我已经说服你这件事有多重要了。别等到躺在临终病床上才去搞明白人生到底是怎么回事。" tabindex="-1">我希望我已经说服你这件事有多重要了。别等到躺在临终病床上才去搞明白人生到底是怎么回事。 <a class="header-anchor" href="#我希望我已经说服你这件事有多重要了。别等到躺在临终病床上才去搞明白人生到底是怎么回事。" aria-label="Permalink to &quot;我希望我已经说服你这件事有多重要了。别等到躺在临终病床上才去搞明白人生到底是怎么回事。&quot;">​</a></h2><p><em>要打印这篇文章或离线阅读,<a href="https://gum.co/religion" target="_blank" rel="noreferrer">试试 PDF 版</a>。</em></p><p><strong>另外三篇 Wait But Why 关于我们每天都应该努力记住的事的文章:</strong></p><p><strong><a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">驯服猛犸象:为什么你应该停止在意别人怎么想</a></strong></p><p><strong><a href="https://waitbutwhy.com/2015/11/the-cook-and-the-chef-musks-secret-sauce.html" target="_blank" rel="noreferrer">厨子与大厨:马斯克的秘方</a><a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer"><br></a></strong></p><h2 id="人生是一幅画-但你活在一个像素里" tabindex="-1"><strong><a href="https://waitbutwhy.com/2013/11/life-is-picture-but-you-live-in-pixel.html" target="_blank" rel="noreferrer">人生是一幅画,但你活在一个像素里</a></strong> <a class="header-anchor" href="#人生是一幅画-但你活在一个像素里" aria-label="Permalink to &quot;**[人生是一幅画,但你活在一个像素里](https://waitbutwhy.com/2013/11/life-is-picture-but-you-live-in-pixel.html)**&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会发给你。</p><p>要支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><hr><ol><li><p>顺便一提,写完这篇文章的提纲之后,我估算写作部分需要 10 个小时——奇怪的是,我现在已经写了大约 8 个小时,却还停在楼梯的第 1 级。你可能会觉得,过去一年我写了大约 50 篇文章,每一篇都低估了所需时间,到现在我应该不至于还这么严重地自欺欺人。你可能会这么以为。</p><p>如果你继续往下想,你可能还会以为,昨天我需要从曼哈顿 116 街赶到世贸中心参加一个绝对不能迟到的活动时,考虑到我根据经验知道这段路通常要花一小时,我至少不会只在活动开始前 40 分钟才出门吧。我们都同意你会这么想。那我为什么最后要冲刺才能准时赶到?为什么我又一次落得满头大汗地赶时间——*这辈子第九万亿次了——*而这种毫无尊严又难受得要死的经历明明这么容易避免?</p><p>因为在我做出这些令人费解的、愚蠢的、自我拆台的决定时,我正泡在雾里游泳。<a href="#note-1-2610">↩</a></p></li><li><p>我用一个奇怪的办法:假装自己有一个旋钮,可以调到某个睡眠小时数,然后按下按钮,瞬间就到了那么多小时以后,并且我已经睡了旋钮上设定的那个小时数,可以继续做原来的事。我是个夜猫子,但如果我真有那个旋钮,我几乎每晚都会 11 点上床、睡 8 小时。这就让我看清一个事实:我其实并不是夜猫子——我的高我 (Higher Being) 是想从 11 点睡到 7 点的——只不过我有一种短视的、雾里雾气的抗拒,不想去睡觉。这大概归根结底又莫名其妙地绕回对死亡的恐惧,真烦。<a href="#note-2-2610">↩</a></p></li><li><p>题外话:<a href="https://www.youtube.com/watch?v=wQr8UWuVefA" target="_blank" rel="noreferrer">https://www.youtube.com/watch?v=wQr8UWuVefA</a><a href="#note-3-2610">↩</a></p></li><li><p>有人质疑这话是不是开尔文说的,认为其实是另一位 19 世纪伟大物理学家阿尔伯特·A·迈克尔逊 (Albert A. Michelson) 说的。不管哪种说法正确,反正是一位伟大的科学家说的。<a href="#note-4-2610">↩</a></p></li><li><p>随着暴胀理论 (inflationary theory) 的流行,这个理论已经过时,但现在有一些著名物理学家开始<a href="http://physicsworld.com/cws/article/news/2014/mar/18/neil-turok-urges-caution-on-bicep2-results" target="_blank" rel="noreferrer">质疑</a>暴胀理论本身的正确性。<a href="#note-5-2610">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/10/religion-for-the-nonreligious.html&amp;description=Religion%20for%20the%20Nonreligious" target="_blank" rel="noreferrer"><img src="'+L+'" alt=""></a></p>',203)])])}const Z=t(R,[["render",I]]);export{Q as __pageData,Z as default};
